from pathlib import Path

class VirtualDocFS:
    def __init__(self, docs_root: str):
        self.root = Path(docs_root)
        self._index = self._build_index()

    def _build_index(self) -> dict:
        index = {}
        for path in self.root.rglob("*.md"):
            rel = path.relative_to(self.root)
            topic = rel.stem.replace("-", "_").lower()
            index[topic] = str(rel)
        return index

    def list_topics(self) -> list[str]:
        return sorted(self._index.keys())

    def read_section(self, topic: str) -> str:
        path = self.root / self._index.get(topic, "")
        if not path.exists():
            return f"Topic '{topic}' not found."
        return path.read_text(encoding="utf-8")[:4000]

def get_tools(docfs):
    return [
        {
            "name": "list_topics",
            "description": "List available doc topics",
            "input_schema": {"type": "object", "properties": {}}
        },
        {
            "name": "read_section",
            "description": "Read docs for a topic",
            "input_schema": {
                "type": "object",
                "properties": {
                    "topic": {"type": "string"},
                    "heading": {"type": "string"}
                },
                "required": ["topic"]
            }
        }
    ]

def handle_tool_call(docfs, name, args):
    if name == "list_topics":
        return docfs.list_topics()
    elif name == "read_section":
        return docfs.read_section(args["topic"], args.get("heading"))

